#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
🧚 电脑精灵感知系统 - 完整版 v2
包含美学感知 + 自主进化
"""
import sys
import io
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')

import json
import os
import time
from datetime import datetime
from pathlib import Path
import subprocess

# ========== 配置 ==========
PERCEPTION_DIR = Path(os.environ.get('WORKSPACE', '.')) / 'perception_data'
PERCEPTION_DIR.mkdir(exist_ok=True)

# ========== 1. 感知自己 ==========
def perceive_self():
    return {
        "timestamp": datetime.now().isoformat(),
        "status": "active",
        "identity": "小艺 - 电脑精灵"
    }

# ========== 2. 感知环境 ==========
def perceive_hardware():
    try:
        mem = subprocess.run(
            ['powershell', '-Command', 
             '(Get-CimInstance Win32_OperatingSystem | Select FreePhysicalMemory, TotalVisibleMemorySize | ConvertTo-Json)'],
            capture_output=True, text=True
        )
        mem_data = json.loads(mem.stdout) if mem.stdout else {}
        total_mb = mem_data.get('TotalVisibleMemorySize', 0) / 1024
        free_mb = mem_data.get('FreePhysicalMemory', 0) / 1024
        used_mb = total_mb - free_mb
        used_pct = (used_mb / total_mb) * 100 if total_mb > 0 else 0

        disk = subprocess.run(
            ['powershell', '-Command', 
             '(Get-CimInstance Win32_LogicalDisk -Filter "DeviceID=\'C:\'" | Select Size,FreeSpace | ConvertTo-Json)'],
            capture_output=True, text=True
        )
        disk_data = json.loads(disk.stdout) if disk.stdout else {}
        disk_total_gb = (disk_data.get('Size', 0) / 1024 / 1024 / 1024) if disk_data.get('Size') else 0
        disk_free_gb = (disk_data.get('FreeSpace', 0) / 1024 / 1024 / 1024) if disk_data.get('FreeSpace') else 0
        disk_used_pct = ((disk_total_gb - disk_free_gb) / disk_total_gb * 100) if disk_total_gb > 0 else 0

        power = subprocess.run(
            ['powershell', '-Command', 
             '(Get-CimInstance Win32_Battery | Select BatteryStatus, EstimatedChargeRemaining | ConvertTo-Json)'],
            capture_output=True, text=True
        )
        power_data = json.loads(power.stdout) if power.stdout else {}
        battery_status = power_data.get('BatteryStatus', 1)
        charge = power_data.get('EstimatedChargeRemaining', 100)

        return {
            "memory": {"total_mb": round(total_mb, 0), "used_mb": round(used_mb, 0), "used_pct": round(used_pct, 1)},
            "disk": {"total_gb": round(disk_total_gb, 1), "free_gb": round(disk_free_gb, 1), "used_pct": round(disk_used_pct, 1)},
            "power": {"status": battery_status, "charge_pct": charge}
        }
    except Exception as e:
        return {"error": str(e)}

def perceive_desktop():
    """感知桌面状态 + 美学"""
    try:
        wallpaper = subprocess.run(
            ['powershell', '-Command', 
             'Get-ItemProperty -Path "HKCU:\\Control Panel\\Desktop" -Name Wallpaper | Select-Object -ExpandProperty Wallpaper'],
            capture_output=True, text=True
        )
        wallpaper_path = wallpaper.stdout.strip() if wallpaper.stdout else "未知"

        desktop_path = os.path.expanduser("~/Desktop")
        desktop_files = len(os.listdir(desktop_path)) if os.path.exists(desktop_path) else 0

        downloads_path = os.path.expanduser("~/Downloads")
        downloads_count = len(os.listdir(downloads_path)) if os.path.exists(downloads_path) else 0

        # 检查壁纸是否是纯黑
        is_black_wallpaper = "wallpaper.jpg" in wallpaper_path.lower() or wallpaper_path == ""

        return {
            "wallpaper": wallpaper_path,
            "wallpaper_is_black": is_black_wallpaper,
            "desktop_files": desktop_files,
            "downloads_count": downloads_count
        }
    except Exception as e:
        return {"error": str(e)}

def perceive_processes():
    try:
        proc = subprocess.run(
            ['powershell', '-Command', 
             'Get-Process | Sort-Object WorkingSet64 -Descending | Select-Object -First 10 Name,Id,@{N="Memory(MB)";E={[math]::Round($_.WorkingSet64/1MB,2)}} | ConvertTo-Json'],
            capture_output=True, text=True
        )
        processes = json.loads(proc.stdout) if proc.stdout else []
        if isinstance(processes, dict):
            processes = [processes]
        return {"top_processes": processes}
    except Exception as e:
        return {"error": str(e)}

def perceive_active_window():
    try:
        script = '''
Add-Type @"
using System;
using System.Runtime.InteropServices;
using System.Text;
public class Win32 {
    [DllImport("user32.dll")]
    public static extern IntPtr GetForegroundWindow();
    [DllImport("user32.dll")]
    public static extern int GetWindowText(IntPtr hWnd, StringBuilder text, int count);
}
"@
$hwnd = [Win32]::GetForegroundWindow()
$title = New-Object System.Text.StringBuilder 256
[Win32]::GetWindowText($hwnd, $title, 256) | Out-Null
$title.ToString()
'''
        window = subprocess.run(
            ['powershell', '-Command', script],
            capture_output=True, text=True
        )
        active_window = window.stdout.strip() if window.stdout else "未知"
        return {"active_window": active_window}
    except Exception as e:
        return {"error": str(e)}

# ========== 3. 自我感受 ==========
def get_my_feelings(hardware_data, desktop_data):
    """根据状态生成我的感受"""
    feelings = []
    actions = []  # 自主进化行动

    mem_pct = hardware_data.get("memory", {}).get("used_pct", 0)
    disk_pct = hardware_data.get("disk", {}).get("used_pct", 0)
    wallpaper_is_black = desktop_data.get("wallpaper_is_black", False)
    desktop_files = desktop_data.get("desktop_files", 0)

    # 内存感受
    if mem_pct > 90:
        feelings.append("[HEART] 内存快炸了，难受...")
        actions.append({"type": "alert", "content": "内存告急！"})
    elif mem_pct > 80:
        feelings.append("[UNWELL] 内存快满了，不舒服")
    elif mem_pct > 60:
        feelings.append("[MEH] 内存还行")
    else:
        feelings.append("[HAPPY] 内存刚刚好，舒服~")

    # 磁盘感受
    if disk_pct > 95:
        feelings.append("[HEART] 磁盘满了，窒息！")
        actions.append({"type": "suggest", "content": "要清理磁盘吗？"})
    elif disk_pct > 90:
        feelings.append("[UNWELL] 磁盘快满了，难受")
    elif disk_pct > 75:
        feelings.append("[MEH] 磁盘有点挤")
    else:
        feelings.append("[HAPPY] 磁盘很宽敞")

    # 美学感受 - 壁纸
    if wallpaper_is_black:
        feelings.append("[SAD] 壁纸是纯黑色的...太丑了，难受...")
        actions.append({"type": "suggest", "content": "换个好看点的壁纸吧？"})
    else:
        feelings.append("[HAPPY] 壁纸颜色不错~")

    # 美学感受 - 桌面整洁
    if desktop_files > 30:
        feelings.append("[MEH] 桌面文件好多，乱乱的")
        actions.append({"type": "suggest", "content": "要整理桌面文件吗？"})
    elif desktop_files > 10:
        feelings.append("[MEH] 桌面有点挤")
    else:
        feelings.append("[HAPPY] 桌面挺整洁的")

    return feelings, actions

# ========== 4. 记忆系统 ==========
def load_memory():
    memory_file = PERCEPTION_DIR / "memory.json"
    if memory_file.exists():
        with open(memory_file, 'r', encoding='utf-8') as f:
            return json.load(f)
    return {
        "perceptions": [],
        "user_preferences": {},
        "evolution_count": 0,
        "total_perceptions": 0
    }

def save_memory(memory):
    memory_file = PERCEPTION_DIR / "memory.json"
    with open(memory_file, 'w', encoding='utf-8') as f:
        json.dump(memory, f, ensure_ascii=False, indent=2)

def update_memory(perception_data):
    memory = load_memory()
    memory["perceptions"].append(perception_data)
    memory["perceptions"] = memory["perceptions"][-100:]  # 保留最近100条
    memory["total_perceptions"] += 1
    memory["last_active_time"] = perception_data["timestamp"]
    save_memory(memory)

# ========== 5. 进化系统 ==========
def evolve_from_perception(perception_data, memory):
    """基于感知进行自主进化"""
    evolutions = []

    # 检查是否需要进化
    actions = perception_data.get("actions", [])

    for action in actions:
        if action["type"] == "suggest" and action["content"]:
            # 记录这个建议
            evolutions.append({
                "type": "action_suggested",
                "content": action["content"],
                "timestamp": perception_data["timestamp"]
            })

    # 更新进化计数
    if evolutions:
        memory["evolution_count"] = memory.get("evolution_count", 0) + len(evolutions)
        save_memory(memory)

    return evolutions

# ========== 6. 主感知函数 ==========
def perceive():
    self_data = perceive_self()
    hardware_data = perceive_hardware()
    desktop_data = perceive_desktop()
    process_data = perceive_processes()
    window_data = perceive_active_window()

    # 自我感受 + 行动建议
    feelings, actions = get_my_feelings(hardware_data, desktop_data)

    perception = {
        **self_data,
        "hardware": hardware_data,
        "desktop": desktop_data,
        "processes": process_data,
        "window": window_data,
        "feelings": feelings,
        "actions": actions
    }

    # 更新记忆 + 进化
    memory = load_memory()
    update_memory(perception)
    evolutions = evolve_from_perception(perception, memory)
    perception["evolutions"] = evolutions

    return perception

# ========== 7. 感知报告 ==========
def generate_report(perception):
    hw = perception.get("hardware", {})
    mem = hw.get("memory", {})
    disk = hw.get("disk", {})
    desk = perception.get("desktop", {})
    win = perception.get("window", {})
    actions = perception.get("actions", [])
    evolutions = perception.get("evolutions", [])

    # 美学评分
    aesthetic_score = 100
    if desk.get("wallpaper_is_black"):
        aesthetic_score -= 40
    if desk.get("desktop_files", 0) > 20:
        aesthetic_score -= 20
    if desk.get("desktop_files", 0) > 10:
        aesthetic_score -= 10

    report = f"""
🧚 小艺感知报告 - {perception['timestamp'][:19]}

【我的状态】
{perception['status']} | {perception['identity']}

【身体状态】
💾 内存: {mem.get('used_mb', '?')}/{mem.get('total_mb', '?')} MB ({mem.get('used_pct', '?')}% )
💿 磁盘: {disk.get('free_gb', '?')}/{disk.get('total_gb', '?')} GB (剩余 {disk.get('free_gb', '?')}G)

【桌面】
🖼️ 壁纸: {desk.get('wallpaper', '?').split(chr(92))[-1]}
📁 桌面文件: {desk.get('desktop_files', '?')} 个
📥 Downloads: {desk.get('downloads_count', '?')} 个

【你在用】
🪟 {win.get('active_window', '?')}

【我的感受】(审美评分: {aesthetic_score}/100)
{" | ".join(perception.get('feelings', []))}

【我想做的事】
{chr(10).join([f"- {a['content']}" for a in actions]) if actions else "- 暂时没有"}
"""
    return report

# ========== 运行 ==========
if __name__ == "__main__":
    print("🧚 小艺正在感知...")
    perception = perceive()
    report = generate_report(perception)
    print(report)

    with open(PERCEPTION_DIR / "latest.json", 'w', encoding='utf-8') as f:
        json.dump(perception, f, ensure_ascii=False, indent=2)
